from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('localhost', 27017)
db = client.cms

@app.route('/add_profile', methods=['POST'])
def add_profile():
    data = request.json
    db.profiles.insert_one(data)
    return jsonify({'message': 'Profile added successfully'}), 201

@app.route('/get_profiles', methods=['GET'])
def get_profiles():
    profiles = list(db.profiles.find())
    for profile in profiles:
        profile['_id'] = str(profile['_id'])
    return jsonify(profiles), 200

@app.route('/get_profile/<string:username>', methods=['GET'])
def get_profile(username):
    profile = db.profiles.find_one({'username': username})
    if profile:
        profile['_id'] = str(profile['_id'])
        return jsonify(profile), 200
    return jsonify({'message': 'Profile not found'}), 404

@app.route('/aggregate_profiles', methods=['GET'])
def aggregate_profiles():
    pipeline = [
        {'$match': {'age': {'$gte': 30}}},
        {'$group': {'_id': '$country', 'count': {'$sum': 1}}},
        {'$sort': {'count': -1}}
    ]
    result = list(db.profiles.aggregate(pipeline))
    return jsonify(result), 200

if __name__ == '__main__':
    app.run(debug=True)